local Config = require("__enemyracemanager__/lib/global_config")
local String = require("__erm_libs__/stdlib/string")
local PickerDollies = {}

PickerDollies.events = {
    [Config.custom_event_handlers[Config.EVENT_FLUSH_GLOBAL]] = function(event)
        local epd_api = remote.interfaces['PickerDollies']
        if epd_api then
            for idx, entity in pairs(prototypes.get_entity_filtered{{filter = "type", type = "radar"}}) do
                local nameToken = String.split(entity.name, "--")
                if nameToken[2] == 'psi-radar' then
                    log('ERM: Adding psi radar to PickerDollies add_blacklist_name '..entity.name)
                    remote.call('PickerDollies', 'add_blacklist_name', entity.name)
                end
            end
        end
    end
}

return PickerDollies